from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
import sqlite3

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Initialize database
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, username TEXT UNIQUE, password_hash TEXT, mfa_enabled BOOLEAN, mfa_secret TEXT)''')
    conn.commit()
    conn.close()

# User model
class User:
    def __init__(self, id, username, password_hash, mfa_enabled, mfa_secret):
        self.id = id
        self.username = username
        self.password_hash = password_hash
        self.mfa_enabled = mfa_enabled
        self.mfa_secret = mfa_secret

    @staticmethod
    def get_by_username(username):
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("SELECT * FROM users WHERE username=?", (username,))
        row = c.fetchone()
        conn.close()
        if row:
            return User(row[0], row[1], row[2], row[3], row[4])
        return None

    @staticmethod
    def create(username, password, mfa_secret=None):
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        password_hash = generate_password_hash(password)
        mfa_enabled = mfa_secret is not None
        c.execute("INSERT INTO users (username, password_hash, mfa_enabled, mfa_secret) VALUES (?, ?, ?, ?)",
                  (username, password_hash, mfa_enabled, mfa_secret))
        conn.commit()
        conn.close()

# Authentication routes
@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = User.get_by_username(username)
    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['user_id'] = user.id
    session['username'] = user.username
    
    if user.mfa_enabled:
        return jsonify({'mfa_required': True, 'message': 'Please enter your OTP'})
    else:
        return jsonify({'message': 'Login successful', 'access_token': 'dummy-token'})

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    data = request.get_json()
    otp = data.get('otp')
    
    if 'user_id' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    user = User.get_by_username(session['username'])
    if not user:
        return jsonify({'error': 'User not found'}), 401
    
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(otp):
        return jsonify({'error': 'Invalid OTP'}), 401
    
    session['mfa_verified'] = True
    return jsonify({'message': 'Login successful', 'access_token': 'dummy-token'})

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = User.get_by_username(username)
    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    return jsonify({'message': 'Login successful', 'access_token': 'dummy-token'})

# Initialize database on startup
init_db()

if __name__ == '__main__':
    app.run(debug=True)